UPDATE SETTING_CODE
SET
    SETTING_NAME = #{settingName},
    DEFAULT_YN = #{defaultYn},
    USE_YN = #{useYn}
WHERE SETTING_CODE_ID = #{settingCodeId}

mapper.select:
SELECT COUNT(*)
FROM SETTING_CODE
WHERE USER_ID = #{userId}
  AND GROUP_NAME = #{groupName}
  AND DEFAULT_YN = 'Y'

SELECT COUNT(*)
FROM SETTING_CODE
WHERE USER_ID = #{userId}
  AND GROUP_NAME = #{groupName}
  AND SETTING_NAME = #{settingName}
